1735→void phys_apply_rot(object *obj,vms_vector *force_vec)
1736→{
1737→	fix	rate, vecmag;
1738→
1739→	if (obj->movement_type != MT_PHYSICS)
1740→		return;
1741→
1742→	vecmag = vm_vec_mag(force_vec)/8;
1743→	if (vecmag < F1_0/256)
1744→		rate = 4*F1_0;
1745→	else if (vecmag < obj->mtype.phys_info.mass >> 14)
1746→		rate = 4*F1_0;
1747→	else {
1748→		rate = fixdiv(obj->mtype.phys_info.mass, vecmag);
1749→		if (obj->type == OBJ_ROBOT) {
1750→			if (rate < F1_0/4)
1751→				rate = F1_0/4;
1752→			//	Changed by mk, 10/24/95, claw guys should not slow down when attacking!
1753→			if (!Robot_info[obj->id].thief && !Robot_info[obj->id].attack_type) {
1754→				if (obj->ctype.ai_info.SKIP_AI_COUNT * FrameTime < 3*F1_0/4) {
1755→					fix	tval = fixdiv(F1_0, 8*FrameTime);
1756→					int	addval;
1757→
1758→					addval = f2i(tval);
1759→
1760→					if ( (P_Rand() * 2) < (tval & 0xffff))
1761→						addval++;
1762→					obj->ctype.ai_info.SKIP_AI_COUNT += addval;
1763→					// -- mk: too much stuff making hard to see my debug messages...mprintf((0, "FrameTime = %7.3f, addval = %i\n", f2fl(FrameTime), addval));
1764→				}
1765→			}
1766→		} else {
1767→			if (rate < F1_0/2)
1768→				rate = F1_0/2;
1769→		}
1770→	}
1771→
1772→	//	Turn amount inversely proportional to mass.  Third parameter is seconds to do 360 turn.
1773→	physics_turn_towards_vector(force_vec, obj, rate);
