1673→void physics_turn_towards_vector(vms_vector *goal_vector, object *obj, fix rate)
1674→{
1675→#ifdef USE_OX_BRIDGE
1676→	static int ox_bridge_logged = 0;
1677→	if (!ox_bridge_logged)
1678→	{
1679→		fprintf(stderr, "[OX] physics_turn_towards_vector using cd_ox_physics_turn_towards_vector.\n");
1680→		ox_bridge_logged = 1;
1681→	}
1682→	vms_vector *rotvel_ptr = &obj->mtype.phys_info.rotvel;
1683→	int32_t out_rx, out_ry, out_rz;
1684→	cd_ox_physics_turn_towards_vector(
1685→		goal_vector->x, goal_vector->y, goal_vector->z,
1686→		obj->orient.fvec.x, obj->orient.fvec.y, obj->orient.fvec.z,
1687→		rate, (obj->control_type == CT_MORPH) ? 1 : 0,
1688→		rotvel_ptr->x, rotvel_ptr->y, rotvel_ptr->z,
1689→		&out_rx, &out_ry, &out_rz);
1690→	rotvel_ptr->x = out_rx;
1691→	rotvel_ptr->y = out_ry;
1692→	rotvel_ptr->z = out_rz;
1693→#else
1694→	vms_angvec	dest_angles, cur_angles;
1695→	fix			delta_p, delta_h;
1696→	vms_vector	*rotvel_ptr = &obj->mtype.phys_info.rotvel;
1697→
1698→	// Make this object turn towards the goal_vector.  Changes orientation, doesn't change direction of movement.
1699→	// If no one moves, will be facing goal_vector in 1 second.
1700→
1701→	//	Detect null vector.
1702→	if ((goal_vector->x == 0) && (goal_vector->y == 0) && (goal_vector->z == 0))
1703→		return;
1704→
1705→	//	Make morph objects turn more slowly.
1706→	if (obj->control_type == CT_MORPH)
1707→		rate *= 2;
1708→
1709→	vm_extract_angles_vector(&dest_angles, goal_vector);
1710→	vm_extract_angles_vector(&cur_angles, &obj->orient.fvec);
1711→
1712→	delta_p = (dest_angles.p - cur_angles.p);
1713→	delta_h = (dest_angles.h - cur_angles.h);
1714→
1715→	if (delta_p > F1_0/2) delta_p = dest_angles.p - cur_angles.p - F1_0;
1716→	if (delta_p < -F1_0/2) delta_p = dest_angles.p - cur_angles.p + F1_0;
1717→	if (delta_h > F1_0/2) delta_h = dest_angles.h - cur_angles.h - F1_0;
1718→	if (delta_h < -F1_0/2) delta_h = dest_angles.h - cur_angles.h + F1_0;
1719→
1720→	delta_p = fixdiv(delta_p, rate);
1721→	delta_h = fixdiv(delta_h, rate);
