//Simulate a physics object for this frame
void do_physics_sim(object *obj)
{
#ifdef USE_OX_BRIDGE
	Assert(obj->type != OBJ_NONE);
	Assert(obj->movement_type == MT_PHYSICS);

#ifndef NDEBUG
	if (Dont_move_ai_objects)
		if (obj->control_type == CT_AI)
			return;
#endif

