void ai_do_actual_firing_stuff(object *obj, ai_static *aip, ai_local *ailp, robot_info *robptr, vms_vector *vec_to_player, fix dist_to_player, vms_vector *gun_point, int player_visibility, int object_animates, int gun_num)
{
	fix	dot;

	if ((player_visibility == 2) || (Dist_to_last_fired_upon_player_pos < FIRE_AT_NEARBY_PLAYER_THRESHOLD )) {
		vms_vector	fire_pos;

		fire_pos = Believed_player_pos;

		//	Hack: If visibility not == 2, we're here because we're firing at a nearby player.
		//	So, fire at Last_fired_upon_player_pos instead of the player position.
		if (!robptr->attack_type && (player_visibility != 2))
			fire_pos = Last_fired_upon_player_pos;

		//	Changed by mk, 01/04/95, onearm would take about 9 seconds until he can fire at you.
		//	Above comment corrected.  Date changed from 1994, to 1995.  Should fix some very subtle bugs, as well as not cause me to wonder, in the future, why I was writing AI code for onearm ten months before he existed.
		if (!object_animates || ready_to_fire(robptr, ailp)) {
			dot = vm_vec_dot(&obj->orient.fvec, vec_to_player);
			if ((dot >= 7*F1_0/8) || ((dot > F1_0/4) &&  robptr->boss_flag)) {

				if (gun_num < Robot_info[obj->id].n_guns) {
					if (robptr->attack_type == 1) {
						if (!Player_exploded && (dist_to_player < obj->size + ConsoleObject->size + F1_0*2)) {		// robptr->circle_distance[Difficulty_level] + ConsoleObject->size) {
							if (!ai_multiplayer_awareness(obj, ROBOT_FIRE_AGITATION-2))
								return;
							do_ai_robot_hit_attack(obj, ConsoleObject, &obj->pos);
						} else {
							// mprintf((0, "Green won't fire: Too far: dist = %7.3f, threshold = %7.3f\n", f2fl(dist_to_player), f2fl(obj->size + ConsoleObject->size + F1_0*2)));
							return;
						}
					} else {
						if ((gun_point->x == 0) && (gun_point->y == 0) && (gun_point->z == 0)) {
							; //mprintf((0, "Would like to fire gun, but gun not selected.\n"));
						} else {
							if (!ai_multiplayer_awareness(obj, ROBOT_FIRE_AGITATION))
								return;
							//	New, multi-weapon-type system, 06/05/95 (life is slipping away...)
							if (gun_num != 0) {
								if (ailp->next_fire <= 0) {
									ai_fire_laser_at_player(obj, gun_point, gun_num, &fire_pos);
									Last_fired_upon_player_pos = fire_pos;
								}

								if ((ailp->next_fire2 <= 0) && (robptr->weapon_type2 != -1)) {
									calc_gun_point(gun_point, obj, 0);
									ai_fire_laser_at_player(obj, gun_point, 0, &fire_pos);
									Last_fired_upon_player_pos = fire_pos;
								}

							} else if (ailp->next_fire <= 0) {
								ai_fire_laser_at_player(obj, gun_point, gun_num, &fire_pos);
								Last_fired_upon_player_pos = fire_pos;
							}
						}
					}

					//	Wants to fire, so should go into chase mode, probably.
					if ( (aip->behavior != AIB_RUN_FROM)
						 && (aip->behavior != AIB_STILL)
						 && (aip->behavior != AIB_SNIPE)
						 && (aip->behavior != AIB_FOLLOW)
						 && (!robptr->attack_type)
						 && ((ailp->mode == AIM_FOLLOW_PATH) || (ailp->mode == AIM_STILL)))
						ailp->mode = AIM_CHASE_OBJECT;
				}

				aip->GOAL_STATE = AIS_RECO;
				ailp->goal_state[aip->CURRENT_GUN] = AIS_RECO;

				// Switch to next gun for next fire.  If has 2 gun types, select gun #1, if exists.
				aip->CURRENT_GUN++;
				if (aip->CURRENT_GUN >= Robot_info[obj->id].n_guns)
					if ((Robot_info[obj->id].n_guns == 1) || (Robot_info[obj->id].weapon_type2 == -1))
						aip->CURRENT_GUN = 0;
					else
						aip->CURRENT_GUN = 1;
			}
		}
	} else if (!robptr->attack_type && (Weapon_info[Robot_info[obj->id].weapon_type].homing_flag == 1) || ((Robot_info[obj->id].weapon_type2 != -1) && (Weapon_info[Robot_info[obj->id].weapon_type2].homing_flag == 1))) {
		//	Robots which fire homing weapons might fire even if they don't have a bead on the player.
		if (((!object_animates) || (ailp->achieved_state[aip->CURRENT_GUN] == AIS_FIRE))
			 && (((ailp->next_fire <= 0) && (aip->CURRENT_GUN != 0)) || ((ailp->next_fire2 <= 0) && (aip->CURRENT_GUN == 0)))
			 && (vm_vec_dist_quick(&Hit_pos, &obj->pos) > F1_0*40)) {
			if (!ai_multiplayer_awareness(obj, ROBOT_FIRE_AGITATION))
				return;
			ai_fire_laser_at_player(obj, gun_point, gun_num, &Believed_player_pos);

			aip->GOAL_STATE = AIS_RECO;
			ailp->goal_state[aip->CURRENT_GUN] = AIS_RECO;

			// Switch to next gun for next fire.
			aip->CURRENT_GUN++;
			if (aip->CURRENT_GUN >= Robot_info[obj->id].n_guns)
				aip->CURRENT_GUN = 0;
		} else {
			// Switch to next gun for next fire.
			aip->CURRENT_GUN++;
			if (aip->CURRENT_GUN >= Robot_info[obj->id].n_guns)
				aip->CURRENT_GUN = 0;
		}
	} else {


	//	---------------------------------------------------------------

		vms_vector	vec_to_last_pos;

		if (P_Rand()/2 < fixmul(FrameTime, (Difficulty_level << 12) + 0x4000)) {
		if ((!object_animates || ready_to_fire(robptr, ailp)) && (Dist_to_last_fired_upon_player_pos < FIRE_AT_NEARBY_PLAYER_THRESHOLD)) {
			vm_vec_normalized_dir_quick(&vec_to_last_pos, &Believed_player_pos, &obj->pos);
			dot = vm_vec_dot(&obj->orient.fvec, &vec_to_last_pos);
			if (dot >= 7*F1_0/8) {

				if (aip->CURRENT_GUN < Robot_info[obj->id].n_guns) {
					if (robptr->attack_type == 1) {
						if (!Player_exploded && (dist_to_player < obj->size + ConsoleObject->size + F1_0*2)) {		// robptr->circle_distance[Difficulty_level] + ConsoleObject->size) {
							if (!ai_multiplayer_awareness(obj, ROBOT_FIRE_AGITATION-2))
								return;
							do_ai_robot_hit_attack(obj, ConsoleObject, &obj->pos);
						} else {
							// mprintf((0, "Green won't fire: Too far: dist = %7.3f, threshold = %7.3f\n", f2fl(dist_to_player), f2fl(obj->size + ConsoleObject->size + F1_0*2)));
							return;
						}
					} else {
						if ((gun_point->x == 0) && (gun_point->y == 0) && (gun_point->z == 0)) {
							; //mprintf((0, "Would like to fire gun, but gun not selected.\n"));
						} else {
							if (!ai_multiplayer_awareness(obj, ROBOT_FIRE_AGITATION))
								return;
							//	New, multi-weapon-type system, 06/05/95 (life is slipping away...)
							if (gun_num != 0) {
								if (ailp->next_fire <= 0)
									ai_fire_laser_at_player(obj, gun_point, gun_num, &Last_fired_upon_player_pos);

								if ((ailp->next_fire2 <= 0) && (robptr->weapon_type2 != -1)) {
									calc_gun_point(gun_point, obj, 0);
									ai_fire_laser_at_player(obj, gun_point, 0, &Last_fired_upon_player_pos);
								}

							} else if (ailp->next_fire <= 0)
								ai_fire_laser_at_player(obj, gun_point, gun_num, &Last_fired_upon_player_pos);
						}
					}

					//	Wants to fire, so should go into chase mode, probably.
					if ( (aip->behavior != AIB_RUN_FROM) && (aip->behavior != AIB_STILL) && (aip->behavior != AIB_SNIPE) && (aip->behavior != AIB_FOLLOW) && ((ailp->mode == AIM_FOLLOW_PATH) || (ailp->mode == AIM_STILL)))
						ailp->mode = AIM_CHASE_OBJECT;
				}
				aip->GOAL_STATE = AIS_RECO;
				ailp->goal_state[aip->CURRENT_GUN] = AIS_RECO;

  then retry_count := !retry_count - 1);
(* Player seglist tracking *)
if obj_type = obj_player
then (
  if
    !n_phys_segs > 0
    && n_segs > 0
    && phys_seglist.(!n_phys_segs - 1) = seglist.(0)
  then n_phys_segs := !n_phys_segs - 1;
  let i = ref 0 in
  while !i < n_segs && !n_phys_segs < max_fvi_segs - 1 do
    phys_seglist.(!n_phys_segs) <- seglist.(!i);
    n_phys_segs := !n_phys_segs + 1;
    i := !i + 1
  done);
if hit_seg = -1
then (
  (* Horrible error — kill weapons, break *)
  if obj_type = obj_weapon then cur_flags := !cur_flags lor of_should_be_dead;
  (* break *)
  ())
else (
  let save_pos_x = !cur_pos_x in
  let save_pos_y = !cur_pos_y in
  let save_pos_z = !cur_pos_z in
  let save_seg = !cur_segnum in
  cur_pos_x := hit_px;
  cur_pos_y := hit_py;
  cur_pos_z := hit_pz;
  if hit_seg <> !cur_segnum
  then (
    Effect.perform (Obj_relink (objnum, hit_seg));
    cur_segnum := hit_seg);
  (* Check if position is valid *)
  let centermask =
    Effect.perform
      (Get_seg_masks (!cur_pos_x, !cur_pos_y, !cur_pos_z, !cur_segnum))
  in
  if centermask <> 0
  then (
    let n = Effect.perform (Find_object_seg objnum) in
    if n = -1
    then (
      if obj_type = obj_player
      then (
        let n2 =
          Effect.perform
            (Find_point_seg (last_pos_x, last_pos_y, last_pos_z, !cur_segnum))
        in
        if n2 <> -1
        then (
          cur_pos_x := last_pos_x;
          cur_pos_y := last_pos_y;
          cur_pos_z := last_pos_z;
          Effect.perform (Obj_relink (objnum, n2));
          cur_segnum := n2)
        else (
          let cx, cy, cz = Effect.perform (Compute_segment_center !cur_segnum) in
          cur_pos_x := cx + objnum;
          cur_pos_y := cy;
          cur_pos_z := cz))
      else (
        let cx, cy, cz = Effect.perform (Compute_segment_center !cur_segnum) in
        cur_pos_x := cx + objnum;
        cur_pos_y := cy;
        cur_pos_z := cz);
      if obj_type = obj_weapon then cur_flags := !cur_flags lor of_should_be_dead)
    else ();
    (* C does unconditional return when centermask != 0 *)
    early_return := true);
  if not !early_return
  then (
    (* Calculate new sim_time *)
    let moved_time = ref 0 in
    let _actual_dist, (mn_x, mn_y, mn_z) =
      Ox_math.vm_vec_normalized_dir
        ~v_end:(!cur_pos_x, !cur_pos_y, !cur_pos_z)
        ~v_start:(save_pos_x, save_pos_y, save_pos_z)
    in
    let actual_dist = _actual_dist in
    if
      fate = hit_wall
      && Ox_math.vm_vec_dotprod ~a:(mn_x, mn_y, mn_z) ~b:(fvx, fvy, fvz) < 0
    then (
      (* Moved backwards — restore position *)
      cur_pos_x := save_pos_x;
      cur_pos_y := save_pos_y;
      cur_pos_z := save_pos_z;
      Effect.perform (Obj_relink (objnum, save_seg));
      cur_segnum := save_seg;
      moved_time := 0)
    else (
      let attempted_dist = Ox_math.vm_vec_mag ~v:(fvx, fvy, fvz) in
      let old_sim_time = !sim_time in
      sim_time
      := Ox_math.fixmuldiv
           ~a:!sim_time
           ~b:(attempted_dist - actual_dist)
           ~c:attempted_dist;
      moved_time := old_sim_time - !sim_time;
      if !sim_time < 0 || !sim_time > old_sim_time
      then (
        sim_time := old_sim_time;
        moved_time := 0));
    (* Collision response *)
    match fate with
    | f when f = hit_wall ->
      let mv_x, mv_y, mv_z =
        Ox_math.vm_vec_sub
          ~a:(!cur_pos_x, !cur_pos_y, !cur_pos_z)
          ~b:(save_pos_x, save_pos_y, save_pos_z)
      in
      let wall_part =
        Ox_math.vm_vec_dotprod ~a:(mv_x, mv_y, mv_z) ~b:(wn_x, wn_y, wn_z)
      in
      if
        wall_part <> 0
        && !moved_time > 0
        && -Ox_math.fixdiv ~a:wall_part ~b:!moved_time > 0
      then (
        let hit_speed = -Ox_math.fixdiv ~a:wall_part ~b:!moved_time in
        let new_flags =
          Effect.perform
            (Collide_object_with_wall
               ( hit_speed
               , hit_side_seg
               , hit_side
               , hit_px
               , hit_py
               , hit_pz
               , !cur_flags ))
        in
        cur_flags := new_flags)
      else (
        let new_flags =
          Effect.perform
            (Scrape_object_on_wall (hit_side_seg, hit_side, hit_px, hit_py, hit_pz))
        in
        cur_flags := new_flags);
      if not (!cur_flags land of_should_be_dead <> 0)
      then
        if !cur_phys_flags land pf_stick <> 0
        then (
          (* Stick to wall *)
          Effect.perform (Add_stuck_object (hit_side_seg, hit_side));
          cur_vel_x := 0;
          cur_vel_y := 0;
          cur_vel_z := 0;
          obj_stopped := true;
          try_again := false)
        else (
          (* Slide along wall *)
          let wall_part2 =
            Ox_math.vm_vec_dotprod
              ~a:(wn_x, wn_y, wn_z)
              ~b:(!cur_vel_x, !cur_vel_y, !cur_vel_z)
          in
          let wall_part2 =
            if !cur_phys_flags land pf_bounce <> 0
            then wall_part2 * 2
            else wall_part2
          in
          let nvx, nvy, nvz =
            Ox_math.vm_vec_scale_add2
              ~dest:(!cur_vel_x, !cur_vel_y, !cur_vel_z)
              ~src:(wn_x, wn_y, wn_z)
              ~k:(-wall_part2)
          in
          cur_vel_x := nvx;
          cur_vel_y := nvy;
