 86→//find the point on the specified plane where the line intersects
 87→//returns true if point found, false if line parallel to plane
 88→//new_pnt is the found point on the plane
 89→//plane_pnt & plane_norm describe the plane
 90→//p0 & p1 are the ends of the line
 91→int find_plane_line_intersection(vms_vector *new_pnt,vms_vector *plane_pnt,vms_vector *plane_norm,vms_vector *p0,vms_vector *p1,fix rad)
 92→{
 93→	vms_vector d,w;
 94→	fix num,den;
 95→
 96→	vm_vec_sub(&d,p1,p0);
 97→	vm_vec_sub(&w,p0,plane_pnt);
 98→
 99→	num =  vm_vec_dot(plane_norm,&w);
100→	den = -vm_vec_dot(plane_norm,&d);
101→
102→//Why does this assert hit so often
103→//	Assert(num > -rad);
104→
105→	num -= rad;			//move point out by rad
106→
107→	//check for various bad values
108→
109→	if ( (den==0) ||					//moving parallel to wall, so can't hit it
110→		  (den>0) &&
111→			( (num>den) ||				//frac greater than one
112→		     (-num>>15)>=den) ||	//will overflow (large negative)
113→		  (den<0 && num<den))		//frac greater than one
114→		return 0;
115→ 
116→//if (num>0) {mprintf(1,"HEY! num>0 in FVI!!!"); return 0;}
117→//??	Assert(num>=0);
118→//    Assert(num >= den);
119→
120→	//do check for potenial overflow
121→	{
122→		fix k;
123→
124→		if (labs(num)/(f1_0/2) >= labs(den)) {Int3(); return 0;}
125→		k = fixdiv(num,den);
126→
127→		Assert(k<=f1_0);		//should be trapped above
128→
129→//		Assert(k>=0);
130→		if (oflow_check(d.x,k) || oflow_check(d.y,k) || oflow_check(d.z,k)) return 0;
131→		//Note: it is ok for k to be greater than 1, since this might mean
132→		//that an object with a non-zero radius that moved from p0 to p1 
133→		//actually hit the wall on the "other side" of p0.
134→	}
135→
136→	vm_vec_scale2(&d,num,den);
137→
138→	vm_vec_add(new_pnt,p0,&d);
139→
140→	//we should have vm_vec_scale2_add2()
141→
142→	return 1;
143→
144→}
