402→//this version is for when the start and end positions both poke through
403→//the plane of a side.  In this case, we must do checks against the edge
404→//of faces
405→int special_check_line_to_face(vms_vector *newp,vms_vector *p0,vms_vector *p1,segment *seg,int side,int facenum,int nv,fix rad)
406→{
407→	if (disable_new_fvi_stuff)
408→		return check_line_to_face(newp,p0,p1,seg,side,facenum,nv,rad);
409→
410→	if ((seg-Segments)==-1)
411→		Error("segnum == -1 in special_check_line_to_face()");
412→
413→	{
414→	vms_vector move_vec;
415→	fix edge_t,move_t,edge_t2,move_t2,closest_dist;
416→	fix edge_len,move_len;
417→	int vertex_list[6];
418→	int num_faces,edgenum;
419→	uint32_t edgemask;
420→	vms_vector *edge_v0,*edge_v1,edge_vec;
421→	struct side *s=&seg->sides[side];
422→	vms_vector closest_point_edge,closest_point_move;
423→
424→	//calc some basic stuff
425→
426→	create_abs_vertex_lists(&num_faces,vertex_list,seg-Segments,side);
427→	vm_vec_sub(&move_vec,p1,p0);
428→
429→	//figure out which edge(s) to check against
430→
431→	edgemask = check_point_to_face(p0,s,facenum,nv,vertex_list);
432→
433→	if (edgemask == 0)
434→		return check_line_to_face(newp,p0,p1,seg,side,facenum,nv,rad);
435→
436→	for (edgenum=0;!(edgemask&1);edgemask>>=1,edgenum++);
437→
438→	edge_v0 = &Vertices[vertex_list[facenum*3+edgenum]];
439→	edge_v1 = &Vertices[vertex_list[facenum*3+((edgenum+1)%nv)]];
440→
441→	vm_vec_sub(&edge_vec,edge_v1,edge_v0);
442→
443→	//is the start point already touching the edge?
444→
445→	//??
446→
447→	//first, find point of closest approach of vec & edge
448→
449→	edge_len = vm_vec_normalize(&edge_vec);
450→	move_len = vm_vec_normalize(&move_vec);
451→
452→	check_line_to_line(&edge_t,&move_t,edge_v0,&edge_vec,p0,&move_vec);
453→
454→	//make sure t values are in valid range
455→
456→	if (move_t<0 || move_t>move_len+rad)
457→		return IT_NONE;
458→
459→	if (move_t > move_len)
460→		move_t2 = move_len;
461→	else
462→		move_t2 = move_t;
463→
464→	if (edge_t < 0)		//saturate at points
465→		edge_t2 = 0;
466→	else
467→		edge_t2 = edge_t;
468→
469→	if (edge_t2 > edge_len)		//saturate at points
470→		edge_t2 = edge_len;
471→
472→	//now, edge_t & move_t determine closest points.  calculate the points.
473→
474→	vm_vec_scale_add(&closest_point_edge,edge_v0,&edge_vec,edge_t2);
475→	vm_vec_scale_add(&closest_point_move,p0,&move_vec,move_t2);
476→
477→	//find dist between closest points
478→
479→	closest_dist = vm_vec_dist(&closest_point_edge,&closest_point_move);
480→
481→	//could we hit with this dist?
482→
483→	//note massive tolerance here
484→//	if (closest_dist < (rad*18)/20) {		//we hit.  figure out where
485→	if (closest_dist < (rad*15)/20) {		//we hit.  figure out where
486→
487→		//now figure out where we hit
488→
489→		vm_vec_scale_add(newp,p0,&move_vec,move_t-rad);
490→
491→		return IT_EDGE;
492→
493→	}
494→	else
495→		return IT_NONE;			//no hit
496→	}
