505→int check_vector_to_sphere_1(vms_vector *intp,vms_vector *p0,vms_vector *p1,vms_vector *sphere_pos,fix sphere_rad)
506→{
507→	{
508→	vms_vector d,dn,w,closest_point;
509→	fix mag_d,dist,w_dist,int_dist;
510→
511→	//this routine could be optimized if it's taking too much time!
512→
513→	vm_vec_sub(&d,p1,p0);
514→	vm_vec_sub(&w,sphere_pos,p0);
515→
516→	mag_d = vm_vec_copy_normalize(&dn,&d);
517→
518→	if (mag_d == 0) {
519→		int_dist = vm_vec_mag(&w);
520→		*intp = *p0;
521→		return (int_dist<sphere_rad)?int_dist:0;
522→	}
523→
524→	w_dist = vm_vec_dot(&dn,&w);
525→
526→	if (w_dist < 0)		//moving away from object
527→		 return 0;
528→
529→	if (w_dist > mag_d+sphere_rad)
530→		return 0;		//cannot hit
531→
532→	vm_vec_scale_add(&closest_point,p0,&dn,w_dist);
533→
534→	dist = vm_vec_dist(&closest_point,sphere_pos);
535→
536→	if (dist < sphere_rad) {
537→		fix dist2,rad2,shorten;
538→
539→		dist2 = fixmul(dist,dist);
540→		rad2 = fixmul(sphere_rad,sphere_rad);
541→
542→		shorten = fix_sqrt(rad2 - dist2);
