544→		int_dist = w_dist-shorten;
545→
546→		if (int_dist > mag_d || int_dist < 0) {
547→			//past one or the other end of vector, which means we're inside
548→
549→			*intp = *p0;		//don't move at all
550→			return 1;
551→		}
552→
553→		vm_vec_scale_add(intp,p0,&dn,int_dist);         //calc intersection point
554→
555→//		{
556→//			fix dd = vm_vec_dist(intp,sphere_pos);
557→//			Assert(dd == sphere_rad);
558→//			mprintf(0,"dd=%x, rad=%x, delta=%x\n",dd,sphere_rad,dd-sphere_rad);
559→//		}
560→
561→
562→		return int_dist;
563→	}
564→	else
565→		return 0;
566→	}
567→}
