1296→void find_hitpoint_uv(fix *u,fix *v,fix *l,vms_vector *pnt,segment *seg,int sidenum,int facenum)
1297→{
1298→	vms_vector_array *pnt_array;
1299→	vms_vector_array normal_array;

1300→	int segnum = seg-Segments;
1301→	int num_faces;
1302→	int biggest,ii,jj;
1303→	side *side = &seg->sides[sidenum];
1304→	int vertex_list[6],vertnum_list[6];
1305→ 	vec2d p1,vec0,vec1,checkp;	//@@,checkv;
