1308→	int i;
1309→
1310→	//mprintf(0,"\ncheck_trans_wall  vec=%x,%x,%x\n",pnt->x,pnt->y,pnt->z);
1311→
1312→	//do lasers pass through illusory walls?
1313→
1314→	//when do I return 0 & 1 for non-transparent walls?
1315→
1316→	if (segnum < 0 || segnum > Highest_segment_index) {
1317→		mprintf((0,"Bad segnum (%d) in find_hitpoint_uv()\n",segnum));
1318→		*u = *v = 0;
1319→		return;
1320→	}
1321→
1322→	if (segnum==-1)
1323→		Error("segnum == -1 in find_hitpoint_uv()");
1324→
1325→	create_abs_vertex_lists(&num_faces,vertex_list,segnum,sidenum);
1326→	create_all_vertnum_lists(&num_faces,vertnum_list,segnum,sidenum);
1327→
1328→	//now the hard work.
1329→
1330→	//1. find what plane to project this wall onto to make it a 2d case
1331→
1332→	#ifdef COMPACT_SEGS
1333→		get_side_normal(seg, sidenum, facenum, (vms_vector *)&normal_array );
1334→	#else
1335→		memcpy( &normal_array, &side->normals[facenum], sizeof(vms_vector_array) );
1336→	#endif
1337→  	biggest = 0;
1338→
1339→	if (abs(normal_array.xyz[1]) > abs(normal_array.xyz[biggest])) biggest = 1;
1340→	if (abs(normal_array.xyz[2]) > abs(normal_array.xyz[biggest])) biggest = 2;
1341→
1342→	if (biggest == 0) ii=1; else ii=0;
1343→	if (biggest == 2) jj=1; else jj=2;
1344→
1345→	//2. compute u,v of intersection point
1346→
1347→	//vec from 1 -> 0
1348→	pnt_array = (vms_vector_array *)&Vertices[vertex_list[facenum*3+1]];
1349→	p1.i = pnt_array->xyz[ii];
1350→	p1.j = pnt_array->xyz[jj];
1351→
1352→	pnt_array = (vms_vector_array *)&Vertices[vertex_list[facenum*3+0]];
1353→	vec0.i = pnt_array->xyz[ii] - p1.i;
1354→	vec0.j = pnt_array->xyz[jj] - p1.j;
1355→
1356→	//vec from 1 -> 2
1357→	pnt_array = (vms_vector_array *)&Vertices[vertex_list[facenum*3+2]];
1358→	vec1.i = pnt_array->xyz[ii] - p1.i;
1359→	vec1.j = pnt_array->xyz[jj] - p1.j;
1360→
1361→	//vec from 1 -> checkpoint
1362→	pnt_array = (vms_vector_array *)pnt;
1363→	checkp.i = pnt_array->xyz[ii];
1364→	checkp.j = pnt_array->xyz[jj];
1365→
1366→	//@@checkv.i = checkp.i - p1.i;
1367→	//@@checkv.j = checkp.j - p1.j;
1368→
1369→	//mprintf(0," vec0   = %x,%x  ",vec0.i,vec0.j);
1370→	//mprintf(0," vec1   = %x,%x  ",vec1.i,vec1.j);
1371→	//mprintf(0," checkv = %x,%x\n",checkv.i,checkv.j);
1372→
1373→	k1 = -fixdiv(cross(&checkp,&vec0) + cross(&vec0,&p1),cross(&vec0,&vec1));
1374→	if (abs(vec0.i) > abs(vec0.j))
1375→		k0 = fixdiv(fixmul(-k1,vec1.i) + checkp.i - p1.i,vec0.i);
1376→	else
1377→		k0 = fixdiv(fixmul(-k1,vec1.j) + checkp.j - p1.j,vec0.j);
1378→
1379→	//mprintf(0," k0,k1  = %x,%x\n",k0,k1);
1380→
1381→	for (i=0;i<3;i++)
1382→		uvls[i] = side->uvls[vertnum_list[facenum*3+i]];
1383→
1384→	*u = uvls[1].u + fixmul( k0,uvls[0].u - uvls[1].u) + fixmul(k1,uvls[2].u - uvls[1].u);
1385→	*v = uvls[1].v + fixmul( k0,uvls[0].v - uvls[1].v) + fixmul(k1,uvls[2].v - uvls[1].v);
1386→
1387→	if (l)
1388→		*l = uvls[1].l + fixmul( k0,uvls[0].l - uvls[1].l) + fixmul(k1,uvls[2].l - uvls[1].l);
1389→
1390→	//mprintf(0," u,v    = %x,%x\n",*u,*v);
1391→}
