1415→
1416→	bmx = ((unsigned) f2i(u*bm->bm_w)) % bm->bm_w;
1417→	bmy = ((unsigned) f2i(v*bm->bm_h)) % bm->bm_h;
1418→
1419→//note: the line above had -v, but that was wrong, so I changed it.  if 
