232→int check_sphere_to_face(vms_vector *pnt, side *s,int facenum,int nv,fix rad,int *vertex_list)
233→{
234→	vms_vector checkp=*pnt;
235→	uint32_t edgemask;
236→
237→	//now do 2d check to see if point is in side
238→
239→	edgemask = check_point_to_face(pnt,s,facenum,nv,vertex_list);
240→
241→	//we've gone through all the sides, are we inside?
242→
243→	if (edgemask == 0)
244→		return IT_FACE;
245→	else {
246→		vms_vector edgevec,checkvec;            //this time, real 3d vectors
247→		vms_vector closest_point;
248→		fix edgelen,d,dist;
249→		vms_vector *v0,*v1;
250→		int itype;
251→		int edgenum;
252→
253→		//get verts for edge we're behind
254→
255→		for (edgenum=0;!(edgemask&1);(edgemask>>=1),edgenum++);
256→
257→		v0 = &Vertices[vertex_list[facenum*3+edgenum]];
258→		v1 = &Vertices[vertex_list[facenum*3+((edgenum+1)%nv)]];
259→
260→		//check if we are touching an edge or point
261→
262→		vm_vec_sub(&checkvec,&checkp,v0);
263→		edgelen = vm_vec_normalized_dir(&edgevec,v1,v0);
264→		
265→		//find point dist from planes of ends of edge
266→
267→		d = vm_vec_dot(&edgevec,&checkvec);
268→
269→		if (d+rad < 0) return IT_NONE;                  //too far behind start point
270→
271→		if (d-rad > edgelen) return IT_NONE;    //too far part end point
272→
