		packed[18 + i * 6 + 1] = seg->sides[i].normals[0].y;
		packed[18 + i * 6 + 2] = seg->sides[i].normals[0].z;
		packed[18 + i * 6 + 3] = seg->sides[i].normals[1].x;
		packed[18 + i * 6 + 4] = seg->sides[i].normals[1].y;
		packed[18 + i * 6 + 5] = seg->sides[i].normals[1].z;
