1593→  (* Helper: unpack path state returned by path effects.
1594→     Array: [0]hide_index [1]path_length [2]cur_path_index [3]path_dir
1595→            [4]mode [5]goal_segment [6]time_player_seen [7]player_awareness_type
1596→            [8]behavior [9]hide_segment *)
1597→  let unpack_path_state ps =
1598→    hide_index := ps.(0);
1599→    path_length := ps.(1);
1600→    cur_path_index := ps.(2);
1601→    (* ps.(3) = path_dir: not tracked as ref in OCaml, ignored *)
1602→    mode := ps.(4);
1603→    goal_segment := ps.(5);
1604→    time_player_seen := ps.(6);
1605→    player_awareness_type := ps.(7);
1606→    behavior := ps.(8);
1607→    hide_segment := ps.(9);
1608→    skip_ai_count := ps.(10)
1609→    (* ps.(11) = next_action_time: NOT read back because C's do_snipe_frame/do_thief_frame
1610→       operate on stale next_action_time (OCaml decremented it but didn't write to C).
1611→       OCaml manages next_action_time directly (decrement + snipe_attack reset). *)
1612→  in
1613→  (* Helper: pack result *)
1614→  let pack_result () =
1615→    let r = Array.create ~len:(ai_state_size + 7) 0 in
1616→    r.(idx_skip_ai_count) <- !skip_ai_count;
1617→    r.(idx_goal_state) <- !goal_state;
1618→    r.(idx_current_state) <- !current_state;
