CAMLprim value cd_ox_effect_af_compute_vis_and_vec(
    value v_gpx, value v_gpy, value v_gpz)
{
    CAMLparam0();
    CAMLlocal1(result);
    int32_t pv = 0, vtpx = 0, vtpy = 0, vtpz = 0, sound_flag = 0;
