    result = caml_alloc_tuple(5);
    Store_field(result, 0, Val_long(pv));
    Store_field(result, 1, Val_long(vtpx));
    Store_field(result, 2, Val_long(vtpy));
    Store_field(result, 3, Val_long(vtpz));
    Store_field(result, 4, Val_long(sound_flag));
    CAMLreturn(result);
}

